+using System;
+using Xunit;
+using OracleV5;
+
+namespace OracleV5.Strategy.Tests
+{
+    public class HeartbeatMonitorTests
+    {
+        [Fact]
+        public void IsAlive_ReturnsFalse_WhenEngineNotPulsed()
+        {
+            // Arrange
+            var monitor = new HeartbeatMonitor(TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(15));
+            var utcNow = DateTime.UtcNow;
+
+            // Act
+            bool alive = monitor.IsAlive("UnknownEngine", utcNow);
+
+            // Assert
+            Assert.False(alive);
+        }
+
+        [Fact]
+        public void IsAlive_ReturnsTrue_WhenEngineRecentlyPulsed()
+        {
+            // Arrange
+            var monitor = new HeartbeatMonitor(TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(15));
+            var engineName = "TestEngine";
+            var lastPulse = DateTime.UtcNow;
+            var checkTime = lastPulse.AddSeconds(10); // Less than 15s stale threshold
+
+            monitor.Pulse(engineName, lastPulse);
+
+            // Act
+            bool alive = monitor.IsAlive(engineName, checkTime);
+
+            // Assert
+            Assert.True(alive);
+        }
+
+        [Fact]
+        public void IsAlive_ReturnsFalse_WhenEnginePulseIsStale()
+        {
+            // Arrange
+            var monitor = new HeartbeatMonitor(TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(15));
+            var engineName = "TestEngine";
+            var lastPulse = DateTime.UtcNow;
+            var checkTime = lastPulse.AddSeconds(20); // More than 15s stale threshold
+
+            monitor.Pulse(engineName, lastPulse);
+
+            // Act
+            bool alive = monitor.IsAlive(engineName, checkTime);
+
+            // Assert
+            Assert.False(alive);
+        }
+
+        [Fact]
+        public void IsAlive_ReturnsFalse_WhenEngineNameIsWhitespace()
+        {
+            // Arrange
+            var monitor = new HeartbeatMonitor(TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(15));
+            var utcNow = DateTime.UtcNow;
+
+            // Act
+            bool aliveNull = monitor.IsAlive(null, utcNow);
+            bool aliveEmpty = monitor.IsAlive("", utcNow);
+            bool aliveWhitespace = monitor.IsAlive("   ", utcNow);
+
+            // Assert
+            Assert.False(aliveNull);
+            Assert.False(aliveEmpty);
+            Assert.False(aliveWhitespace);
+        }
+
+        [Fact]
+        public void IsAlive_HandlesDateTimeKindsCorrectly()
+        {
+            // Arrange
+            var monitor = new HeartbeatMonitor(TimeSpan.FromSeconds(5), TimeSpan.FromSeconds(15));
+            var engineName = "TestEngine";
+            var lastPulseUtc = new DateTime(2023, 10, 27, 12, 0, 0, DateTimeKind.Utc);
+            
+            // Pulsing with UTC
+            monitor.Pulse(engineName, lastPulseUtc);
+
+            // Act & Assert
+            
+            // Check with Local time (assuming it's converted to UTC internally by EnsureUtc)
+            var checkTimeLocal = lastPulseUtc.ToLocalTime().AddSeconds(10);
+            Assert.True(monitor.IsAlive(engineName, checkTimeLocal));
+
+            // Check with Unspecified time (assumed UTC by EnsureUtc)
+            var checkTimeUnspecified = new DateTime(lastPulseUtc.Ticks, DateTimeKind.Unspecified).AddSeconds(10);
+            Assert.True(monitor.IsAlive(engineName, checkTimeUnspecified));
+
+            // Check with Stale Unspecified time
+            var staleTimeUnspecified = new DateTime(lastPulseUtc.Ticks, DateTimeKind.Unspecified).AddSeconds(20);
+            Assert.False(monitor.IsAlive(engineName, staleTimeUnspecified));
+        }
+    }
+}
